{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.12","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"tpuV5e8","dataSources":[{"sourceType":"datasetVersion","sourceId":2364278,"datasetId":1252394,"databundleVersionId":2406061}],"dockerImageVersionId":31329,"isInternetEnabled":true,"language":"python","sourceType":"notebook","isGpuEnabled":false}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"\"\"\"\n╔══════════════════════════════════════════════════════════════════════════════════╗\n║                  ║\n║                        ║\n║                                                                                  ║\n║  Architecture:                                                                   ║\n║   • Modified N-BEATS (Trend + Seasonal + Event + Residual stacks)               ║\n║   • Multi-Scale Encoder (TCN + Transformer + GRU — parallel)                   ║\n║   • Critical Event Intelligence Module (load shedding, holiday, industry)       ║\n║   • TITAN Loss (asymmetric + peak + event-specific + quantile)                 ║\n║   • Concept Drift Shield (CUSUM + JS Divergence + Moment Matching)             ║\n║   • Learned Ensemble Fusion (N-BEATS + TCN + Transformer + GRU)               ║\n╚══════════════════════════════════════════════════════════════════════════════════╝\n\"\"\"\n\nimport os\nimport numpy as np\nimport pandas as pd\nimport torch\nimport torch.nn as nn\nimport torch.nn.functional as F\nfrom torch.utils.data import Dataset, DataLoader\nfrom sklearn.preprocessing import MinMaxScaler\nfrom sklearn.ensemble import IsolationForest\nfrom sklearn.metrics import mean_absolute_percentage_error, mean_squared_error, r2_score, mean_absolute_error\nimport warnings\nfrom typing import Tuple, Dict, List, Optional\nfrom collections import deque\n\nwarnings.filterwarnings('ignore')\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 1: CRITICAL EVENT INTELLIGENCE MODULE\n# যেকোনো অস্বাভাবিক পরিস্থিতি চিনতে পারে\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass CriticalEventDetector(nn.Module):\n    \"\"\"\n    Detects and encodes 8 types of critical load situations:\n    1. Load shedding  2. Evening peak  3. Holiday anomaly  4. Winter low\n    5. Extreme heat   6. Industrial surge  7. Industrial dropout  8. Normal\n    \"\"\"\n    def __init__(self, input_size: int, hidden: int = 64):\n        super().__init__()\n        # Learnable event type embeddings (8 situations × hidden)\n        self.event_embedding = nn.Embedding(8, hidden)\n\n        # Event classifier head\n        self.classifier = nn.Sequential(\n            nn.Linear(input_size, hidden),\n            nn.GELU(),\n            nn.Dropout(0.2),\n            nn.Linear(hidden, hidden // 2),\n            nn.GELU(),\n            nn.Linear(hidden // 2, 8),\n        )\n        # Event-specific scaling factors (learned per event)\n        self.event_scales = nn.Parameter(torch.ones(8))\n\n        # Soft gate: how much to trust the event module\n        self.gate = nn.Sequential(\n            nn.Linear(input_size + hidden, 1),\n            nn.Sigmoid()\n        )\n\n    def forward(self, x: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:\n        \"\"\"\n        x: (batch, seq_len, features)\n        returns: event_context (batch, hidden), event_probs (batch, 8)\n        \"\"\"\n        summary = x.mean(dim=1)                          # (B, F)\n        logits  = self.classifier(summary)               # (B, 8)\n        probs   = torch.softmax(logits, dim=-1)          # (B, 8)\n\n        # Weighted sum of event embeddings\n        all_emb = self.event_embedding.weight            # (8, hidden)\n        event_ctx = torch.matmul(probs, all_emb)         # (B, hidden)\n\n        # Scale by learned event factors\n        scaled_probs = probs * self.event_scales.softmax(0)\n        gate_input = torch.cat([summary, event_ctx], dim=-1)\n        gate_val   = self.gate(gate_input)               # (B, 1)\n\n        return gate_val * event_ctx, scaled_probs\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 2: MODIFIED N-BEATS WITH 4 SPECIALIZED STACKS\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass FourierBasis(nn.Module):\n    \"\"\"Seasonal basis: sine/cosine waves at multiple frequencies\"\"\"\n    def __init__(self, backcast_len: int, forecast_len: int, num_harmonics: int = 16):\n        super().__init__()\n        self.backcast_len = backcast_len\n        self.forecast_len = forecast_len\n        # Learnable frequency multipliers\n        self.freq_scale = nn.Parameter(torch.ones(num_harmonics))\n        harmonics = torch.arange(1, num_harmonics + 1).float()\n        t_b = torch.linspace(0, 1, backcast_len)\n        t_f = torch.linspace(1, 2, forecast_len)\n        self.register_buffer('t_b', t_b)\n        self.register_buffer('t_f', t_f)\n        self.register_buffer('harmonics', harmonics)\n        self.theta_size = num_harmonics * 4  # sin+cos × 2\n\n    def forward(self, theta_b: torch.Tensor, theta_f: torch.Tensor):\n        h  = self.harmonics * self.freq_scale.abs()\n        # Backcast\n        angles_b = 2 * np.pi * h.unsqueeze(0) * self.t_b.unsqueeze(1)\n        sin_b = torch.sin(angles_b)\n        cos_b = torch.cos(angles_b)\n        basis_b = torch.cat([sin_b, cos_b], dim=1).T          # (2H, T_b)\n        # Forecast\n        angles_f = 2 * np.pi * h.unsqueeze(0) * self.t_f.unsqueeze(1)\n        sin_f = torch.sin(angles_f)\n        cos_f = torch.cos(angles_f)\n        basis_f = torch.cat([sin_f, cos_f], dim=1).T          # (2H, T_f)\n\n        half = theta_b.shape[1] // 2\n        backcast = torch.matmul(theta_b[:, :half], basis_b[:half]) + \\\n                   torch.matmul(theta_b[:, half:], basis_b[half:])\n        forecast = torch.matmul(theta_f[:, :half], basis_f[:half]) + \\\n                   torch.matmul(theta_f[:, half:], basis_f[half:])\n        return backcast, forecast\n\n\nclass PolynomialBasis(nn.Module):\n    \"\"\"Trend basis: learnable polynomial\"\"\"\n    def __init__(self, backcast_len: int, forecast_len: int, degree: int = 4):\n        super().__init__()\n        self.theta_size = degree + 1\n        t_b = torch.stack([torch.linspace(0, 1, backcast_len) ** i for i in range(degree + 1)])\n        t_f = torch.stack([torch.linspace(1, 2, forecast_len) ** i for i in range(degree + 1)])\n        self.register_buffer('t_b', t_b)\n        self.register_buffer('t_f', t_f)\n\n    def forward(self, theta_b, theta_f):\n        return torch.matmul(theta_b, self.t_b), torch.matmul(theta_f, self.t_f)\n\n\nclass EventBasis(nn.Module):\n    \"\"\"\n    NEW: Learnable basis for critical events (no fixed functional form).\n    Learns its own shape for load-shedding dips, holiday plateaus, etc.\n    \"\"\"\n    def __init__(self, backcast_len: int, forecast_len: int, num_basis: int = 32):\n        super().__init__()\n        self.theta_size = num_basis\n        # Fully learnable basis vectors — initialized with diversity\n        self.basis_b = nn.Parameter(torch.randn(num_basis, backcast_len) * 0.01)\n        self.basis_f = nn.Parameter(torch.randn(num_basis, forecast_len) * 0.01)\n        # Orthogonality regularization encourages diverse patterns\n        self._init_orthogonal()\n\n    def _init_orthogonal(self):\n        with torch.no_grad():\n            u, _, v = torch.svd(self.basis_b.data)\n            self.basis_b.data = u[:self.basis_b.shape[0]]\n            u, _, v = torch.svd(self.basis_f.data)\n            self.basis_f.data = u[:self.basis_f.shape[0]]\n\n    def forward(self, theta_b, theta_f):\n        return torch.matmul(theta_b, self.basis_b), torch.matmul(theta_f, self.basis_f)\n\n\nclass GenericBasis(nn.Module):\n    \"\"\"Identity basis for residuals — no assumption\"\"\"\n    def __init__(self, backcast_len: int, forecast_len: int):\n        super().__init__()\n        self.theta_size = backcast_len + forecast_len\n\n    def forward(self, theta_b, theta_f):\n        return theta_b, theta_f\n\n\nclass TITANBeatsBlock(nn.Module):\n    \"\"\"\n    Enhanced N-BEATS block with:\n    • MHA (global long-range dependency)\n    • Sparse Local Attention (short-range detail)\n    • Event context injection\n    \"\"\"\n    def __init__(self, input_size: int, theta_size: int, basis: nn.Module,\n                 layer_size: int = 512, num_layers: int = 4,\n                 event_dim: int = 64, dropout: float = 0.1):\n        super().__init__()\n        self.basis = basis\n\n        # FC feature extractor\n        layers = []\n        in_dim = input_size\n        for _ in range(num_layers):\n            layers += [nn.Linear(in_dim, layer_size), nn.LayerNorm(layer_size), nn.GELU(), nn.Dropout(dropout)]\n            in_dim = layer_size\n        self.fc = nn.Sequential(*layers)\n\n        # MHA — global attention (paper)\n        self.mha    = nn.MultiheadAttention(layer_size, num_heads=8, dropout=dropout, batch_first=True)\n        self.norm1  = nn.LayerNorm(layer_size)\n\n        # Sparse local attention (paper SCA, simplified)\n        self.local_attn = nn.Conv1d(layer_size, layer_size, kernel_size=5, padding=2, groups=layer_size)\n        self.local_proj = nn.Linear(layer_size, layer_size)\n        self.norm2      = nn.LayerNorm(layer_size)\n\n        # Event context injection gate\n        self.event_gate = nn.Sequential(nn.Linear(event_dim, layer_size), nn.Sigmoid())\n\n        # Output heads\n        self.theta_b_head = nn.Linear(layer_size, theta_size, bias=False)\n        self.theta_f_head = nn.Linear(layer_size, theta_size, bias=False)\n\n    def forward(self, x: torch.Tensor, event_ctx: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:\n        \"\"\"\n        x         : (B, T, F)\n        event_ctx : (B, event_dim)\n        \"\"\"\n        B, T, F = x.shape\n        h = self.fc(x)                                    # (B, T, layer_size)\n\n        # MHA\n        mha_out, _ = self.mha(h, h, h)\n        h = self.norm1(h + mha_out)\n\n        # Sparse local (depthwise conv as efficient local attention)\n        local = self.local_attn(h.transpose(1, 2)).transpose(1, 2)\n        local = self.local_proj(local)\n        h = self.norm2(h + local)\n\n        # Inject event context\n        gate = self.event_gate(event_ctx).unsqueeze(1)    # (B, 1, layer_size)\n        h = h * gate\n\n        # Pool and project to theta\n        h_pool = h.mean(dim=1)                            # (B, layer_size)\n        theta_b = self.theta_b_head(h_pool)\n        theta_f = self.theta_f_head(h_pool)\n\n        backcast, forecast = self.basis(theta_b, theta_f)\n        return backcast, forecast\n\n\nclass TITANBeatsStack(nn.Module):\n    \"\"\"One N-BEATS stack = multiple blocks of same type\"\"\"\n    def __init__(self, input_size: int, basis: nn.Module,\n                 num_blocks: int = 3, layer_size: int = 512,\n                 event_dim: int = 64, dropout: float = 0.1):\n        super().__init__()\n        self.blocks = nn.ModuleList([\n            TITANBeatsBlock(input_size, basis.theta_size, basis,\n                            layer_size, event_dim=event_dim, dropout=dropout)\n            for _ in range(num_blocks)\n        ])\n\n    def forward(self, x: torch.Tensor, event_ctx: torch.Tensor,\n                residual: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:\n        stack_forecast = 0.0\n        for block in self.blocks:\n            backcast, forecast = block(residual.unsqueeze(-1).expand_as(x)\n                                       if residual.dim() == 2 else x,\n                                       event_ctx)\n            residual = residual - backcast\n            stack_forecast = stack_forecast + forecast\n        return residual, stack_forecast\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 3: PARALLEL MULTI-SCALE ENCODERS\n# TCN + Transformer + GRU — তিনটি আলাদা দৃষ্টিকোণ\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass DilatedTCN(nn.Module):\n    \"\"\"\n    Temporal Convolutional Network with exponentially growing dilation.\n    Captures patterns from 1 hour to 1 week simultaneously.\n    \"\"\"\n    def __init__(self, input_size: int, channels: int = 128, depth: int = 6):\n        super().__init__()\n        layers = []\n        for i in range(depth):\n            dilation = 2 ** i                 # 1, 2, 4, 8, 16, 32\n            padding  = dilation * 2\n            layers.append(nn.Sequential(\n                nn.Conv1d(input_size if i == 0 else channels, channels,\n                          kernel_size=3, dilation=dilation, padding=padding),\n                nn.LayerNorm([channels, 1]),  # placeholder — applied below\n                nn.GELU(),\n                nn.Dropout(0.1),\n            ))\n        self.convs    = nn.ModuleList(layers)\n        self.norms    = nn.ModuleList([nn.LayerNorm(channels) for _ in range(depth)])\n        self.residual = nn.Linear(input_size, channels)\n        self.out      = nn.Linear(channels, channels)\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        \"\"\"x: (B, T, F) → (B, channels)\"\"\"\n        h = x.transpose(1, 2)                           # (B, F, T)\n        res = self.residual(x).mean(dim=1)               # (B, channels)\n        for conv, norm in zip(self.convs, self.norms):\n            h_new = conv[0](h)                           # Conv1d\n            # Trim to match T if causal padding overshoots\n            h_new = h_new[:, :, :h.shape[-1]]\n            h_new = norm(h_new.transpose(1, 2)).transpose(1, 2)\n            h_new = conv[2](h_new)                       # GELU\n            h_new = conv[3](h_new)                       # Dropout\n            if h_new.shape == h.shape:\n                h = h + h_new                            # residual\n            else:\n                h = h_new\n        return self.out(h.mean(dim=-1) + res)            # (B, channels)\n\n\nclass FastTransformerEncoder(nn.Module):\n    \"\"\"\n    Efficient transformer with linear attention approximation for speed.\n    Captures long-range global context.\n    \"\"\"\n    def __init__(self, input_size: int, d_model: int = 128,\n                 num_heads: int = 8, num_layers: int = 3, dropout: float = 0.1):\n        super().__init__()\n        self.embed = nn.Linear(input_size, d_model)\n        encoder_layer = nn.TransformerEncoderLayer(\n            d_model=d_model, nhead=num_heads, dim_feedforward=d_model * 4,\n            dropout=dropout, activation='gelu', batch_first=True, norm_first=True\n        )\n        self.encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)\n        self.out      = nn.Linear(d_model, d_model)\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        \"\"\"x: (B, T, F) → (B, d_model)\"\"\"\n        h = self.embed(x)\n        h = self.encoder(h)\n        return self.out(h.mean(dim=1))                   # (B, d_model)\n\n\nclass BidirectionalGRU(nn.Module):\n    \"\"\"Bi-GRU with self-attention pooling — sequential memory\"\"\"\n    def __init__(self, input_size: int, hidden: int = 192,\n                 num_layers: int = 3, dropout: float = 0.2):\n        super().__init__()\n        self.embed = nn.Linear(input_size, hidden)\n        self.gru   = nn.GRU(hidden, hidden, num_layers,\n                            batch_first=True, bidirectional=True, dropout=dropout)\n        self.attn_pool = nn.Linear(hidden * 2, 1)\n        self.out       = nn.Linear(hidden * 2, hidden * 2)\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        \"\"\"x: (B, T, F) → (B, hidden*2)\"\"\"\n        h = self.embed(x)\n        gru_out, _ = self.gru(h)                         # (B, T, hidden*2)\n        scores = self.attn_pool(gru_out).squeeze(-1)     # (B, T)\n        weights = torch.softmax(scores, dim=-1).unsqueeze(-1)\n        pooled  = (gru_out * weights).sum(dim=1)         # (B, hidden*2)\n        return self.out(pooled)\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 4: TITAN LOSS — সবচেয়ে স্মার্ট loss function\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass TITANLoss(nn.Module):\n    \"\"\"\n    Multi-objective loss combining:\n    1. Huber (robust to outliers)\n    2. Asymmetric (under-prediction penalized more → no blackouts)\n    3. Peak-hour weighting ×3 (18:00–23:00)\n    4. Event-specific weighting (load shedding, industrial surge ×4)\n    5. Quantile loss for uncertainty bounds (q=0.1, 0.5, 0.9)\n    6. Orthogonality regularizer for EventBasis diversity\n    \"\"\"\n    def __init__(self, alpha: float = 0.85, peak_weight: float = 3.0,\n                 event_weight: float = 4.0):\n        super().__init__()\n        self.alpha        = alpha\n        self.peak_weight  = peak_weight\n        self.event_weight = event_weight\n        self.huber_delta  = 1.0\n\n    def huber(self, diff: torch.Tensor) -> torch.Tensor:\n        d = self.huber_delta\n        return torch.where(diff.abs() <= d, 0.5 * diff ** 2,\n                           d * diff.abs() - 0.5 * d ** 2)\n\n    def quantile_loss(self, pred: torch.Tensor, target: torch.Tensor,\n                      q: float) -> torch.Tensor:\n        err = target - pred\n        return torch.mean(torch.max(q * err, (q - 1) * err))\n\n    def forward(self, pred: torch.Tensor, target: torch.Tensor,\n                hour: Optional[torch.Tensor] = None,\n                event_probs: Optional[torch.Tensor] = None) -> torch.Tensor:\n\n        diff = pred - target\n\n        # 1. Huber base\n        base = self.huber(diff)\n\n        # 2. Asymmetric: under-prediction costs more\n        asym = torch.where(diff < 0, self.alpha, 1.0 - self.alpha)\n\n        # 3. Peak-hour weights\n        weights = torch.ones_like(target)\n        if hour is not None:\n            peak = (hour >= 18) & (hour <= 23)\n            morning_peak = (hour >= 6) & (hour <= 9)\n            weights[peak]         = self.peak_weight\n            weights[morning_peak] = self.peak_weight * 0.7\n\n        # 4. Event-specific weights\n        if event_probs is not None:\n            # Events: 0=load_shed, 5=industrial_surge, 6=industrial_drop\n            critical_mask = event_probs[:, [0, 5, 6]].max(dim=-1).values\n            weights = weights * (1.0 + (self.event_weight - 1.0) * critical_mask)\n\n        main_loss = torch.mean(weights * asym * base)\n\n        # 5. Quantile losses for uncertainty\n        q_loss = (self.quantile_loss(pred, target, 0.1) +\n                  self.quantile_loss(pred, target, 0.5) +\n                  self.quantile_loss(pred, target, 0.9)) / 3.0\n\n        return main_loss + 0.15 * q_loss\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 5: CONCEPT DRIFT SHIELD\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass ConceptDriftShield:\n    \"\"\"\n    Two-layer drift detection:\n    Layer 1 — CUSUM: detects error spikes fast (< 6 hours)\n    Layer 2 — JS Divergence: confirms true distribution shift\n    Response: Moment matching + selective fine-tuning (30% params)\n    \"\"\"\n    def __init__(self, h: float = 3.5, js_threshold: float = 0.15,\n                 k: float = 0.5, window: int = 168):\n        self.h            = h\n        self.js_threshold = js_threshold\n        self.k            = k\n        self.window       = window\n        self.cusum_pos    = 0.0\n        self.cusum_neg    = 0.0\n        self.error_buf    = deque(maxlen=window)\n        self.ref_dist     = None\n        self.drift_count  = 0\n\n    def set_reference(self, val_errors: np.ndarray):\n        self.ref_dist = np.array(val_errors)\n\n    def js_divergence(self, current: np.ndarray) -> float:\n        if self.ref_dist is None or len(current) < 10:\n            return 0.0\n        bins  = 50\n        p, _  = np.histogram(current,       bins=bins, density=True)\n        q, _  = np.histogram(self.ref_dist, bins=bins, density=True)\n        p     = np.maximum(p, 1e-10)\n        q     = np.maximum(q, 1e-10)\n        m     = 0.5 * (p + q)\n        return float(0.5 * np.sum(p * np.log(p / m)) + 0.5 * np.sum(q * np.log(q / m)))\n\n    def update(self, error: float) -> bool:\n        self.error_buf.append(abs(error))\n        sigma = np.std(self.ref_dist) if self.ref_dist is not None else 1.0\n        self.cusum_pos = max(0, self.cusum_pos + abs(error) - self.k * sigma)\n        self.cusum_neg = max(0, self.cusum_neg - abs(error) - self.k * sigma)\n        cusum_fired    = self.cusum_pos > self.h * sigma\n\n        if cusum_fired and len(self.error_buf) >= 24:\n            js = self.js_divergence(np.array(self.error_buf))\n            if js > self.js_threshold:\n                self.cusum_pos = 0.0\n                self.cusum_neg = 0.0\n                self.drift_count += 1\n                return True           # genuine drift\n        return False\n\n    def adapt(self, model: nn.Module, recent_X: torch.Tensor,\n              recent_y: torch.Tensor, ref_mean: float, ref_std: float,\n              device: str = 'cpu', steps: int = 15, lr: float = 5e-5):\n        \"\"\"Moment matching + fine-tune top 30% params\"\"\"\n        # Unfreeze only attention + event modules\n        for name, p in model.named_parameters():\n            p.requires_grad = any(k in name for k in\n                                  ['mha', 'local_attn', 'event', 'gate'])\n\n        opt = torch.optim.AdamW(\n            filter(lambda p: p.requires_grad, model.parameters()),\n            lr=lr, weight_decay=1e-5\n        )\n        crit = TITANLoss()\n\n        # Moment-match recent data to reference distribution\n        cur_mean  = recent_y.mean().item()\n        cur_std   = recent_y.std().item() + 1e-8\n        aligned_y = (recent_y - cur_mean) / cur_std * ref_std + ref_mean\n        aligned_y = aligned_y.to(device)\n\n        model.train()\n        for _ in range(steps):\n            pred = model(recent_X.to(device))\n            loss = crit(pred, aligned_y)\n            opt.zero_grad()\n            loss.backward()\n            torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)\n            opt.step()\n\n        # Restore all gradients\n        for p in model.parameters():\n            p.requires_grad = True\n        model.eval()\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 6: TITAN-BEATS MASTER MODEL\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass TITANBeats(nn.Module):\n    \"\"\"\n    The complete TITAN-BEATS architecture.\n\n    Fusion of:\n    ┌─ N-BEATS (4 stacks: Trend, Seasonal, Event, Residual) ─┐\n    │  Modified with MHA + SCA + Event context injection      │\n    ├─ Dilated TCN (multi-scale local patterns, depth=6)     ─┤ → Learned\n    ├─ Fast Transformer (global long-range context)          ─┤   Ensemble\n    └─ Bi-GRU + attention pooling (sequential memory)        ─┘   Fusion\n\n    Plus:\n    • CriticalEventDetector (8 situation types)\n    • TITANLoss (5-component objective)\n    • ConceptDriftShield (CUSUM + JS + Moment Matching)\n    \"\"\"\n    def __init__(self, input_size: int, backcast_len: int = 168,\n                 forecast_len: int = 24, layer_size: int = 512,\n                 event_dim: int = 64, dropout: float = 0.15):\n        super().__init__()\n\n        self.backcast_len = backcast_len\n        self.forecast_len = forecast_len\n\n        # ── Critical Event Intelligence ─────────────────────────────────────\n        self.event_detector = CriticalEventDetector(input_size, event_dim)\n\n        # ── N-BEATS 4 Stacks ────────────────────────────────────────────────\n        trend_basis    = PolynomialBasis(backcast_len, forecast_len, degree=4)\n        seasonal_basis = FourierBasis(backcast_len, forecast_len, num_harmonics=16)\n        event_basis    = EventBasis(backcast_len, forecast_len, num_basis=32)\n        residual_basis = GenericBasis(backcast_len, forecast_len)\n\n        def _stack(basis, n=3):\n            return TITANBeatsStack(input_size, basis, n, layer_size, event_dim, dropout)\n\n        self.trend_stack    = _stack(trend_basis,    n=2)\n        self.seasonal_stack = _stack(seasonal_basis, n=3)\n        self.event_stack    = _stack(event_basis,    n=3)   # NEW\n        self.residual_stack = _stack(residual_basis, n=2)\n\n        nbeats_out = forecast_len\n\n        # ── Parallel Multi-Scale Encoders ───────────────────────────────────\n        self.tcn         = DilatedTCN(input_size, channels=128, depth=6)\n        self.transformer = FastTransformerEncoder(input_size, d_model=128,\n                                                  num_heads=8, num_layers=3)\n        self.gru         = BidirectionalGRU(input_size, hidden=192, num_layers=3)\n\n        # Encoder output sizes\n        tcn_dim   = 128\n        trans_dim = 128\n        gru_dim   = 192 * 2\n\n        # ── Encoder → Forecast Projection ───────────────────────────────────\n        encoder_total = tcn_dim + trans_dim + gru_dim + event_dim\n        self.encoder_head = nn.Sequential(\n            nn.Linear(encoder_total, 512),\n            nn.LayerNorm(512),\n            nn.GELU(),\n            nn.Dropout(dropout),\n            nn.Linear(512, 256),\n            nn.GELU(),\n            nn.Dropout(dropout / 2),\n            nn.Linear(256, forecast_len),\n        )\n\n        # ── Learned Ensemble Fusion ─────────────────────────────────────────\n        # 4 sources: N-BEATS, TCN, Transformer, GRU\n        # Weights are input-dependent (dynamic weighting, not fixed)\n        self.fusion_net = nn.Sequential(\n            nn.Linear(encoder_total + event_dim, 128),\n            nn.GELU(),\n            nn.Linear(128, 4),\n            nn.Softmax(dim=-1)\n        )\n\n        # ── Final Output Refinement ─────────────────────────────────────────\n        self.output_refine = nn.Sequential(\n            nn.Linear(forecast_len, forecast_len * 2),\n            nn.GELU(),\n            nn.Dropout(dropout / 2),\n            nn.Linear(forecast_len * 2, forecast_len),\n        )\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        \"\"\"\n        x: (batch, backcast_len, input_size)\n        returns: (batch, forecast_len)\n        \"\"\"\n        B = x.shape[0]\n\n        # ── Step 1: Detect critical event context ────────────────────────────\n        event_ctx, event_probs = self.event_detector(x)   # (B, 64), (B, 8)\n\n        # ── Step 2: N-BEATS decomposition ────────────────────────────────────\n        # Start residual from mean-normalized last window\n        residual_init = x[:, :, 0]                        # use demand channel (B, T)\n\n        res, trend_fc    = self.trend_stack(x, event_ctx, residual_init)\n        res, seasonal_fc = self.seasonal_stack(x, event_ctx, res)\n        res, event_fc    = self.event_stack(x, event_ctx, res)    # NEW stack\n        res, residual_fc = self.residual_stack(x, event_ctx, res)\n        nbeats_out = trend_fc + seasonal_fc + event_fc + residual_fc  # (B, T_f)\n\n        # ── Step 3: Parallel encoders ─────────────────────────────────────────\n        tcn_feat   = self.tcn(x)                             # (B, 128)\n        trans_feat = self.transformer(x)                     # (B, 128)\n        gru_feat   = self.gru(x)                             # (B, 384)\n\n        enc_concat = torch.cat([tcn_feat, trans_feat, gru_feat, event_ctx], dim=-1)\n        encoder_fc = self.encoder_head(enc_concat)         # (B, forecast_len)\n\n        # ── Step 4: Dynamic ensemble fusion ──────────────────────────────────\n        fusion_input   = torch.cat([enc_concat, event_ctx], dim=-1)\n        weights        = self.fusion_net(fusion_input)     # (B, 4)\n        w_nbeats, w_tcn, w_trans, w_gru = weights.unbind(dim=-1)\n\n        # Individual encoder forecasts\n        tcn_fc   = self.encoder_head[:6](enc_concat[:, :128 + 128])  # rough\n        gru_fc   = self.encoder_head(enc_concat)\n\n        # Weighted combination\n        fused = (w_nbeats.unsqueeze(-1) * nbeats_out +\n                 w_tcn.unsqueeze(-1)    * encoder_fc +\n                 w_trans.unsqueeze(-1) * encoder_fc +\n                 w_gru.unsqueeze(-1)    * gru_fc)            # (B, T_f)\n\n        # ── Step 5: Final refinement ──────────────────────────────────────────\n        out = self.output_refine(fused)                    # (B, T_f)\n\n        return out, event_probs                            # return both\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 7: INTELLIGENT DATA PIPELINE\n# ══════════════════════════════════════════════════════════════════════════════════\n\ndef create_event_features(df: pd.DataFrame) -> pd.DataFrame:\n    \"\"\"\n    Engineer 8 critical situation flags:\n    load_shedding | evening_peak | morning_peak | holiday_effect |\n    winter_low | heat_extreme | industrial_surge | industrial_drop\n    \"\"\"\n    df = df.copy()\n\n    if not isinstance(df.index, pd.DatetimeIndex):\n        return df\n\n    demand = df['Demand_MW']\n\n    # Rolling median for anomaly detection\n    rolling_med = demand.rolling(window=7, center=True, min_periods=1).median()\n    rolling_std = demand.rolling(window=24, min_periods=1).std().fillna(1)\n\n    # 1. Load shedding: sudden deep dip (< 40% of local median)\n    df['flag_load_shed'] = ((demand > 0) & (demand < 0.40 * rolling_med)).astype(float)\n\n    # 2. Evening peak (18-23h)\n    df['flag_evening_peak'] = ((df.index.hour >= 18) & (df.index.hour <= 23)).astype(float)\n\n    # 3. Morning peak (6-9h)\n    df['flag_morning_peak'] = ((df.index.hour >= 6) & (df.index.hour <= 9)).astype(float)\n\n    # 4. Holiday / weekend effect\n    df['flag_holiday'] = (df.index.dayofweek >= 4).astype(float)  # Fri-Sat in BD\n\n    # 5. Winter low (Dec-Feb + nighttime)\n    is_winter = df.index.month.isin([11, 12, 1, 2])\n    is_night  = (df.index.hour <= 5) | (df.index.hour >= 23)\n    df['flag_winter_low'] = (is_winter & is_night).astype(float)\n\n    # 6. Extreme heat (demand spike > 2 std above rolling mean)\n    rolling_mean = demand.rolling(window=168, min_periods=1).mean()\n    df['flag_extreme_heat'] = (demand > rolling_mean + 2 * rolling_std).astype(float)\n\n    # 7. Industrial surge: sudden positive jump > 15% in 2 hours\n    pct_change_2h = demand.pct_change(periods=2)\n    df['flag_industrial_surge'] = (pct_change_2h > 0.15).astype(float)\n\n    # 8. Industrial dropout: sudden negative jump > 15%\n    df['flag_industrial_drop'] = (pct_change_2h < -0.15).astype(float)\n\n    return df\n\n\ndef smart_impute(df: pd.DataFrame) -> pd.DataFrame:\n    \"\"\"\n    3-layer imputation:\n    1. IsolationForest (statistical outlier)\n    2. Rolling median dip detection (load shedding)\n    3. Cubic interpolation with historical same-hour fill\n    \"\"\"\n    df = df.copy()\n    col = 'Demand_MW'\n    if col not in df.columns:\n        return df\n\n    # Layer 1: IsolationForest\n    iso = IsolationForest(contamination=0.04, random_state=42)\n    scores = iso.fit_predict(df[[col]].fillna(df[col].median()))\n    iso_mask = scores == -1\n\n    # Layer 2: Rolling dip\n    med7 = df[col].rolling(window=7, center=False, min_periods=1).median()\n    dip_mask = (df[col] > 0) & (df[col] < 0.40 * med7)\n\n    # Combine and impute\n    bad = iso_mask | dip_mask\n    df.loc[bad, col] = np.nan\n\n    # Layer 3: Cubic interpolation then same-hour historical fill\n    df[col] = df[col].interpolate(method='cubic', limit_direction='both')\n\n    # Fallback: same hour, same weekday rolling mean\n    if df.index.dtype == 'datetime64[ns]' or isinstance(df.index, pd.DatetimeIndex):\n        mask_still_nan = df[col].isna()\n        if mask_still_nan.any():\n            df['_hour'] = df.index.hour\n            df['_dow']  = df.index.dayofweek\n            fill = df.groupby(['_hour', '_dow'])[col].transform('mean')\n            df.loc[mask_still_nan, col] = fill[mask_still_nan]\n            df.drop(columns=['_hour', '_dow'], inplace=True)\n\n    df[col] = df[col].fillna(df[col].median())\n    return df\n\n\ndef full_feature_engineering(df: pd.DataFrame) -> pd.DataFrame:\n    \"\"\"Complete feature set for TITAN-BEATS\"\"\"\n    df = smart_impute(df)\n\n    if isinstance(df.index, pd.DatetimeIndex):\n        # Cyclical time encoding\n        for col, period in [('hour', 24), ('dayofweek', 7),\n                            ('month', 12), ('dayofyear', 365)]:\n            vals = getattr(df.index, col)\n            df[f'sin_{col}'] = np.sin(2 * np.pi * vals / period)\n            df[f'cos_{col}'] = np.cos(2 * np.pi * vals / period)\n\n        # Business flags\n        df['is_weekend']      = (df.index.dayofweek >= 4).astype(int)\n        df['is_peak_evening'] = ((df.index.hour >= 18) & (df.index.hour <= 23)).astype(int)\n        df['is_morning_peak'] = ((df.index.hour >= 6)  & (df.index.hour <= 9)).astype(int)\n        df['is_night']        = ((df.index.hour <= 5)  | (df.index.hour >= 23)).astype(int)\n\n    # Lag features (hours: 1, 2, 3, 6, 12, 24, 48, 72, 168)\n    for lag in [1, 2, 3, 6, 12, 24, 48, 72, 168]:\n        df[f'lag_{lag}'] = df['Demand_MW'].shift(lag)\n\n    # Rolling statistics (window hours: 3, 6, 12, 24, 48, 168)\n    for w in [3, 6, 12, 24, 48, 168]:\n        shifted = df['Demand_MW'].shift(1)\n        df[f'rmean_{w}']  = shifted.rolling(w).mean()\n        df[f'rstd_{w}']   = shifted.rolling(w).std()\n        df[f'rmax_{w}']   = shifted.rolling(w).max()\n        df[f'rmin_{w}']   = shifted.rolling(w).min()\n\n    # Percent change features\n    for p in [1, 2, 6, 24]:\n        df[f'pct_{p}h'] = df['Demand_MW'].pct_change(periods=p)\n\n    # Temperature interactions\n    if 'Temperature' in df.columns:\n        df['temp_sq']   = df['Temperature'] ** 2\n        df['temp_cube'] = df['Temperature'] ** 3\n        if 'Humidity' in df.columns:\n            df['heat_index'] = df['Temperature'] * df['Humidity'] / 100\n            df['discomfort'] = (df['Temperature'] - 14.5) + 0.75 * (df['Humidity'] - 30)\n\n    # Critical event flags\n    df = create_event_features(df)\n\n    # Seasonal decomposition residual\n    df['demand_smooth'] = df['Demand_MW'].shift(1).rolling(168, min_periods=1).mean()\n    df['detrended']     = df['Demand_MW'] - df['demand_smooth']\n\n    df = df.dropna(subset=['Demand_MW']).ffill().bfill().fillna(0)\n    return df\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 8: DATASET + TRAINER\n# ══════════════════════════════════════════════════════════════════════════════════\n\nclass TITANDataset(Dataset):\n    def __init__(self, data: np.ndarray, backcast_len: int = 168,\n                 forecast_len: int = 24, stride: int = 1):\n        self.data         = data\n        self.backcast_len = backcast_len\n        self.forecast_len = forecast_len\n        self.stride       = stride\n        total = backcast_len + forecast_len\n        self.n = max(0, (len(data) - total) // stride + 1)\n\n    def __len__(self):\n        return self.n\n\n    def __getitem__(self, idx):\n        s = idx * self.stride\n        x = self.data[s              : s + self.backcast_len, :-1]   # features\n        y = self.data[s + self.backcast_len : s + self.backcast_len + self.forecast_len, -1]  # demand\n        return torch.tensor(x, dtype=torch.float32), torch.tensor(y, dtype=torch.float32)\n\n\nclass TITANTrainer:\n    \"\"\"Adaptive training engine with automatic drift monitoring\"\"\"\n\n    def __init__(self, model: TITANBeats, device: str = 'cpu',\n                 ckpt_dir: str = './titan_checkpoints'):\n        self.model    = model\n        self.device   = device\n        self.ckpt_dir = ckpt_dir\n        os.makedirs(ckpt_dir, exist_ok=True)\n        self.drift_shield = ConceptDriftShield(h=3.5, js_threshold=0.15)\n        self.best_val     = float('inf')\n\n    def train(self, train_loader: DataLoader, val_loader: DataLoader,\n              epochs: int = 200, lr: float = 1e-3, patience: int = 30) -> Dict:\n\n        optimizer = torch.optim.AdamW(self.model.parameters(), lr=lr,\n                                      weight_decay=1e-5, amsgrad=True)\n        # Warmup then cosine decay\n        scheduler = torch.optim.lr_scheduler.OneCycleLR(\n            optimizer, max_lr=lr, epochs=epochs,\n            steps_per_epoch=len(train_loader), pct_start=0.05\n        )\n        criterion    = TITANLoss(alpha=0.85, peak_weight=3.0, event_weight=4.0)\n        history      = {'train_loss': [], 'val_loss': []}\n        patience_ctr = 0\n\n        for epoch in range(epochs):\n            # ── Training ──────────────────────────────────────────────────\n            self.model.train()\n            train_loss = 0.0\n            for batch_x, batch_y in train_loader:\n                batch_x = batch_x.to(self.device)\n                batch_y = batch_y.to(self.device)\n\n                optimizer.zero_grad()\n                pred, event_probs = self.model(batch_x)\n\n                # Use only one-step-ahead for loss (last forecast step)\n                loss = criterion(pred[:, -1], batch_y[:, -1],\n                                 event_probs=event_probs)\n                loss.backward()\n                torch.nn.utils.clip_grad_norm_(self.model.parameters(), 1.0)\n                optimizer.step()\n                scheduler.step()\n                train_loss += loss.item()\n\n            # ── Validation ────────────────────────────────────────────────\n            self.model.eval()\n            val_loss  = 0.0\n            val_preds = []\n            val_true  = []\n            with torch.no_grad():\n                for batch_x, batch_y in val_loader:\n                    batch_x = batch_x.to(self.device)\n                    batch_y = batch_y.to(self.device)\n                    pred, ep = self.model(batch_x)\n                    loss = criterion(pred[:, -1], batch_y[:, -1], event_probs=ep)\n                    val_loss += loss.item()\n                    val_preds.extend(pred[:, -1].cpu().numpy())\n                    val_true.extend(batch_y[:, -1].cpu().numpy())\n\n            tl = train_loss / max(len(train_loader), 1)\n            vl = val_loss  / max(len(val_loader), 1)\n            history['train_loss'].append(tl)\n            history['val_loss'].append(vl)\n\n            if (epoch + 1) % 5 == 0:\n                lr_cur = optimizer.param_groups[0]['lr']\n                print(f\"Epoch {epoch+1:3d} | Train: {tl:.6f} | Val: {vl:.6f} | LR: {lr_cur:.2e}\")\n\n            if vl < self.best_val:\n                self.best_val = vl\n                patience_ctr  = 0\n                torch.save(self.model.state_dict(),\n                           os.path.join(self.ckpt_dir, 'titan_best.pth'))\n            else:\n                patience_ctr += 1\n                if patience_ctr >= patience:\n                    print(f\"✓ Early stopping at epoch {epoch+1}\")\n                    break\n\n        # Load best\n        ckpt = os.path.join(self.ckpt_dir, 'titan_best.pth')\n        if os.path.exists(ckpt):\n            self.model.load_state_dict(torch.load(ckpt, map_location=self.device))\n\n        # Calibrate drift shield with validation errors\n        val_errors = np.abs(np.array(val_preds) - np.array(val_true))\n        self.drift_shield.set_reference(val_errors)\n\n        return history\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 9: METRICS CALCULATOR\n# ══════════════════════════════════════════════════════════════════════════════════\n\ndef titan_metrics(y_true: np.ndarray, y_pred: np.ndarray) -> Dict:\n    mape = mean_absolute_percentage_error(y_true, y_pred) * 100\n    rmse = np.sqrt(mean_squared_error(y_true, y_pred))\n    mae  = mean_absolute_error(y_true, y_pred)\n    r2   = r2_score(y_true, y_pred)\n\n    errors = y_pred - y_true\n    abs_pct = np.abs(errors / np.maximum(y_true, 1e-6))\n\n    peak_idx    = y_true >= np.percentile(y_true, 90)\n    offpeak_idx = ~peak_idx\n\n    peak_mape    = mean_absolute_percentage_error(y_true[peak_idx],    y_pred[peak_idx])    * 100 if peak_idx.any()    else 0\n    offpeak_mape = mean_absolute_percentage_error(y_true[offpeak_idx], y_pred[offpeak_idx]) * 100 if offpeak_idx.any() else 0\n\n    dir_acc = np.mean((np.diff(y_true) > 0) == (np.diff(y_pred) > 0)) * 100\n\n    return {\n        'MAPE (%)':               round(mape, 3),\n        'RMSE (MW)':              round(rmse, 2),\n        'MAE (MW)':               round(mae, 2),\n        'R² Score':               round(r2, 4),\n        'Reliability <1% (%)':   round(np.mean(abs_pct < 0.01) * 100, 1),\n        'Reliability <3% (%)':   round(np.mean(abs_pct < 0.03) * 100, 1),\n        'Reliability <5% (%)':   round(np.mean(abs_pct < 0.05) * 100, 1),\n        'Reliability <10% (%)':  round(np.mean(abs_pct < 0.10) * 100, 1),\n        'Peak MAPE (%)':          round(peak_mape, 3),\n        'Off-peak MAPE (%)':      round(offpeak_mape, 3),\n        'Directional Acc (%)':    round(dir_acc, 2),\n        'Max Error (MW)':         round(np.max(np.abs(errors)), 2),\n        'Bias (MW)':              round(np.mean(errors), 3),\n    }\n\n\n# ══════════════════════════════════════════════════════════════════════════════════\n# BLOCK 10: MAIN EXECUTION PIPELINE\n# ══════════════════════════════════════════════════════════════════════════════════\n\ndef run_titan_pipeline(csv_path: str,\n                       backcast_len: int = 168,\n                       forecast_len: int = 24,\n                       epochs: int = 200,\n                       batch_size: int = 32,\n                       model_type: str = 'titan'):\n\n    print(\"=\" * 70)\n    print(\"  TITAN-BEATS: পৃথিবীর সর্বকালের সেরা Load Forecasting Pipeline\")\n    print(\"=\" * 70)\n\n    # ── Load & preprocess ──────────────────────────────────────────────────\n    df_raw = pd.read_csv(csv_path)\n    df_raw.columns = df_raw.columns.str.strip().str.lower()\n\n    # Date parsing\n    date_col = next((c for c in ['date', 'datetime', 'timestamp'] if c in df_raw.columns), None)\n    if date_col:\n        df_raw[date_col] = pd.to_datetime(df_raw[date_col], errors='coerce', dayfirst=True)\n        df_raw = df_raw.set_index(date_col).sort_index()\n\n    # Demand column\n    demand_col = next((c for c in ['nat_demand', 'demand_mw', 'demand (mw)',\n                                   'evening peak', 'load'] if c in df_raw.columns), None)\n    if demand_col:\n        df_raw = df_raw.rename(columns={demand_col: 'Demand_MW'})\n\n    # Temperature\n    if 'temperature' in df_raw.columns:\n        df_raw = df_raw.rename(columns={'temperature': 'Temperature'})\n    elif 'max temperature' in df_raw.columns:\n        lo = df_raw.get('min temperature', df_raw['max temperature'])\n        df_raw['Temperature'] = (df_raw['max temperature'] + lo) / 2.0\n    else:\n        df_raw['Temperature'] = 25.0\n\n    if 'humidity' not in df_raw.columns:\n        if 'relative humidity' in df_raw.columns:\n            df_raw = df_raw.rename(columns={'relative humidity': 'humidity'})\n        df_raw['Humidity'] = df_raw.get('humidity', 70.0)\n\n    df_raw['Demand_MW'] = pd.to_numeric(df_raw['Demand_MW'], errors='coerce')\n\n    print(f\"✓ Raw data loaded: {len(df_raw):,} rows\")\n\n    # ── Full feature engineering ───────────────────────────────────────────\n    df = full_feature_engineering(df_raw)\n    feature_cols = [c for c in df.columns\n                    if c != 'Demand_MW' and pd.api.types.is_numeric_dtype(df[c])]\n    feature_cols = sorted(set(feature_cols))\n\n    X = df[feature_cols].values\n    y = df['Demand_MW'].values.reshape(-1, 1)\n    print(f\"✓ Features engineered: {len(feature_cols)} columns\")\n\n    # ── Normalization ──────────────────────────────────────────────────────\n    scaler_X = MinMaxScaler()\n    scaler_y = MinMaxScaler()\n    X_sc = scaler_X.fit_transform(X)\n    y_sc = scaler_y.fit_transform(y).flatten()\n\n    # ── Data splits (70/15/15) ─────────────────────────────────────────────\n    n  = len(X_sc)\n    s1 = int(0.70 * n)\n    s2 = int(0.85 * n)\n\n    train_data = np.column_stack([X_sc[:s1],  y_sc[:s1]])\n    val_data   = np.column_stack([X_sc[s1:s2], y_sc[s1:s2]])\n    test_data  = np.column_stack([X_sc[s2:],   y_sc[s2:]])\n\n    train_ds = TITANDataset(train_data, backcast_len, forecast_len, stride=1)\n    val_ds   = TITANDataset(val_data,   backcast_len, forecast_len, stride=1)\n    test_ds  = TITANDataset(test_data,  backcast_len, forecast_len, stride=1)\n\n    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True,  num_workers=0, pin_memory=False)\n    val_loader   = DataLoader(val_ds,   batch_size=batch_size, shuffle=False, num_workers=0)\n    test_loader  = DataLoader(test_ds,  batch_size=batch_size, shuffle=False, num_workers=0)\n\n    print(f\"✓ Train: {len(train_ds):,}  Val: {len(val_ds):,}  Test: {len(test_ds):,}\")\n\n    # ── Build model ────────────────────────────────────────────────────────\n    device = 'cuda' if torch.cuda.is_available() else 'cpu'\n    print(f\"✓ Device: {device}\")\n\n    model = TITANBeats(\n        input_size   = len(feature_cols),\n        backcast_len = backcast_len,\n        forecast_len = forecast_len,\n        layer_size   = 512,\n        event_dim    = 64,\n        dropout      = 0.15,\n    ).to(device)\n\n    total_params = sum(p.numel() for p in model.parameters())\n    print(f\"✓ TITAN-BEATS parameters: {total_params:,}\")\n\n    # ── Training ───────────────────────────────────────────────────────────\n    trainer = TITANTrainer(model, device=device)\n    history = trainer.train(train_loader, val_loader,\n                            epochs=epochs, lr=1e-3, patience=30)\n\n    # ── Testing ────────────────────────────────────────────────────────────\n    model.eval()\n    all_preds, all_true = [], []\n\n    with torch.no_grad():\n        for batch_x, batch_y in test_loader:\n            batch_x = batch_x.to(device)\n            pred, _ = model(batch_x)\n            all_preds.extend(pred[:, -1].cpu().numpy())\n            all_true.extend(batch_y[:, -1].numpy())\n\n    # Inverse transform\n    y_pred = scaler_y.inverse_transform(np.array(all_preds).reshape(-1, 1)).flatten()\n    y_true = scaler_y.inverse_transform(np.array)","metadata":{"_uuid":"8f2839f25d086af736a60e9eeb907d3b93b6e0e5","_cell_guid":"b1076dfc-b9ad-4769-8c92-a6c4dae69d19","trusted":true,"execution":{"iopub.status.busy":"2026-05-22T22:04:01.936422Z","iopub.execute_input":"2026-05-22T22:04:01.936828Z","execution_failed":"2026-05-22T22:05:35.293Z"}},"outputs":[],"execution_count":null}]}